protected override void OnModelCreating(ModelBuilder modelBuilder)
{
    modelBuilder.Entity<Product>(entity =>
    {
        entity.ToContainer("Products");

        // EF Core 9 changed the default discriminator property from "Discriminator" to "$type".
        // Existing 500K documents and direct SQL queries reference c.Discriminator — keep the old name.
        entity.HasDiscriminator<string>("Discriminator");

        // EF Core 9 no longer includes the discriminator in the JSON id by default.
        // Existing documents have ids like "Product|123" — preserve that format.
        entity.HasRootDiscriminatorInJsonId(true);
    });
}

