arguments.new_str:
class CosmosQuery
{
    // EF Core 9 Cosmos provider no longer supports synchronous I/O — use async.
    async Task FindProducts(ProductContext ctx)
    {
        // Direct Cosmos SQL — still works because we configured HasDiscriminator("Discriminator")
        // to keep the old property name. Without that config, EF Core 9 would use "$type" instead.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";
        // Sync APIs (ToList, SaveChanges, etc.) now throw on the Cosmos provider — use async.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

