10. 
11.             // EF Core 9 changed the default discriminator property from "Discriminator" to "$type".
12.             // Existing 500K documents and direct SQL queries reference c.Discriminator — keep the old name.
13.             entity.HasDiscriminator<string>("Discriminator");
